    'xP/G/8j/yv/N/8//0f/U/9b/2f/c/97/4P/j/+X/5//p/+v/7f/v//D/8v/z'...
    '//X/9v/3//j/+f/7//z//f/9//7//////wAAAAAAAAAAAAAAAAAAAAAAAAAA'];

raw_bytes  = matlab.net.base64decode(b64_str);
raw_int16  = typecast(uint8(raw_bytes), 'int16');
audio_tx   = double(raw_int16(:)) / 32767;

fprintf('Decoded: %d samples @ %d Hz (%.3f sec)\n', ...
        length(audio_tx), fs_audio_tx, length(audio_tx)/fs_audio_tx);

%% Pre-emphasis 50us (standard FM broadcast)
alpha    = exp(-1/(50e-6 * fs_audio_tx));
audio_tx = filter([1, -alpha], 1, audio_tx);
audio_tx = audio_tx / (max(abs(audio_tx)) + 1e-9);

%% FM modulate — single buffer
fprintf('FM modulating...\n');
ph     = cumsum(audio_tx) / fs_audio_tx;
fm_sig = exp(1j * 2*pi * max_freq_dev * ph);
fm_sig = fm_sig / max(abs(fm_sig));

fprintf('Upsampling x%d → %.1f MHz...\n', interp_factor, fs_pluto/1e6);
fm_up  = resample(fm_sig, interp_factor, 1);
fm_up  = fm_up / (max(abs(fm_up)) + 1e-9);
fm_up  = single(fm_up * 0.9);

fprintf('TX buffer: %d samples (%.3f sec) — within 16,777,216 limit\n\n', ...
        length(fm_up), length(fm_up)/fs_pluto);

assert(length(fm_up) <= 16777216, 'Buffer too large!');

%% Connect PlutoSDR
fprintf('Connecting to PlutoSDR...\n');
try
    tx = sdrtx('Pluto','RadioID',pluto_uri,...
               'CenterFrequency',fc,...
               'BasebandSampleRate',fs_pluto,...
               'Gain',tx_gain);
catch
    fprintf('IP failed, trying USB...\n');
    tx = sdrtx('Pluto','RadioID','usb:0',...
               'CenterFrequency',fc,...
               'BasebandSampleRate',fs_pluto,...
               'Gain',tx_gain);
end

fprintf('\n>>> Tune FM radio to %.1f MHz! <<<\n', fc/1e6);
fprintf('Seamless loop — zero crossing trimmed, crossfaded.\n');
fprintf('Press Ctrl+C to stop.\n\n');

%% Single transmitRepeat — hardware loops buffer with zero CPU involvement
transmitRepeat(tx, fm_up);

loop_dur = length(fm_up) / fs_pluto;
t0 = tic;
try
    while true
        elapsed = toc(t0);
        loop_n  = floor(elapsed / loop_dur) + 1;
        pos     = mod(elapsed, loop_dur);
        fprintf('\r  Loop #%d | %.2f / %.2f sec | %.0f sec total on %.1f MHz  ', ...
                loop_n, pos, loop_dur, elapsed, fc/1e6);
        pause(0.2);
    end
catch
end

release(tx);
fprintf('\nTransmission stopped.\n');
